import{_ as o,C as l,o as s,c as n,E as a,w as i,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const f=JSON.parse('{"title":"Poland Healthcare & HRT","description":"Transgender healthcare access in Poland","frontmatter":{"layout":"doc","title":"Poland Healthcare & HRT","description":"Transgender healthcare access in Poland"},"headers":[],"relativePath":"europe/poland/healthcare.md","filePath":"europe/poland/healthcare.md","lastUpdated":null}'),c={name:"europe/poland/healthcare.md"};function h(u,e,g,p,m,y){const t=l("Badge");return s(),n("div",null,[a(t,{variant:"red"},{default:i(()=>[...e[0]||(e[0]=[r("Gatekeeping Model",-1)])]),_:1}),a(t,{variant:"yellow"},{default:i(()=>[...e[1]||(e[1]=[r("Sexuology Clinics",-1)])]),_:1}),a(t,{variant:"yellow"},{default:i(()=>[...e[2]||(e[2]=[r("Long Wait Times",-1)])]),_:1}),e[3]||(e[3]=d('<h1 id="healthcare-hrt-in-poland" tabindex="-1">Healthcare &amp; HRT in Poland <a class="header-anchor" href="#healthcare-hrt-in-poland" aria-label="Permalink to &quot;Healthcare &amp; HRT in Poland&quot;">​</a></h1><h2 id="gatekeeping-model" tabindex="-1">Gatekeeping Model <a class="header-anchor" href="#gatekeeping-model" aria-label="Permalink to &quot;Gatekeeping Model&quot;">​</a></h2><p>Poland&#39;s transgender healthcare operates through a <strong>sexuology-based gatekeeping model</strong>:</p><ul><li><strong>Psychiatric/sexuology diagnosis required</strong> for access to HRT</li><li>Services concentrated in major cities (Warsaw, Kraków, Poznań, Wrocław)</li><li>Long wait times for initial appointments (4-12 months)</li><li>Growing but still very limited trans-competent providers</li></ul><h2 id="accessing-hrt" tabindex="-1">Accessing HRT <a class="header-anchor" href="#accessing-hrt" aria-label="Permalink to &quot;Accessing HRT&quot;">​</a></h2><h3 id="step-1-sexuology-assessment" tabindex="-1">Step 1: Sexuology Assessment <a class="header-anchor" href="#step-1-sexuology-assessment" aria-label="Permalink to &quot;Step 1: Sexuology Assessment&quot;">​</a></h3><ul><li>Contact a sexuology clinic (public or private) in a major city</li><li>Public options: Institute of Psychiatry and Neurology (Warsaw), university hospitals</li><li>Private options: Available with shorter wait times but higher costs</li><li>Diagnosis of gender dysphoria per ICD-10/11</li><li>Multiple sessions over 3-6 months</li></ul><h3 id="step-2-endocrinology-referral" tabindex="-1">Step 2: Endocrinology Referral <a class="header-anchor" href="#step-2-endocrinology-referral" aria-label="Permalink to &quot;Step 2: Endocrinology Referral&quot;">​</a></h3><ul><li>Referral to an endocrinologist for hormone therapy</li><li>Baseline blood tests required</li><li>HRT prescribed and monitored</li><li>Follow-up visits every 3-6 months initially</li></ul><h3 id="step-3-ongoing-care" tabindex="-1">Step 3: Ongoing Care <a class="header-anchor" href="#step-3-ongoing-care" aria-label="Permalink to &quot;Step 3: Ongoing Care&quot;">​</a></h3><ul><li>Regular monitoring by endocrinologist</li><li>Some GPs may manage HRT after specialist establishes treatment</li><li>Medications generally available at pharmacies</li></ul><h2 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th></tr></thead><tbody><tr><td>Institute of Psychiatry and Neurology</td><td>Warsaw</td><td>Sexuology, assessment</td></tr><tr><td>University Hospital</td><td>Kraków</td><td>Sexuology, endocrinology</td></tr><tr><td>Poznań University Medical Center</td><td>Poznań</td><td>Sexuology, HRT</td></tr><tr><td>Wrocław Medical University</td><td>Wrocław</td><td>Sexuology, HRT</td></tr><tr><td>Private sexuologists</td><td>Major cities</td><td>Assessment (shorter waits)</td></tr></tbody></table><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><ul><li><strong>EU prescriptions</strong>: Valid in Poland under EU mutual recognition</li><li><strong>Non-EU prescriptions</strong>: Must be re-evaluated by a Polish doctor</li><li><strong>Importing medication</strong>: 3-month supply permitted with a doctor&#39;s letter</li><li><strong>Medication availability</strong>: Generally good in major cities</li><li><strong>Pharmacies</strong>: Major chains (Ziko, Apteka, DOZ) nationwide</li></ul><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><ul><li><strong>Very limited surgical options</strong> in Poland</li><li>Some top surgery available (primarily private)</li><li>Bottom surgery: Very limited, virtually unavailable domestically</li><li>Most travel abroad (Thailand, Germany, Belgium, Spain)</li><li>No public funding for gender-affirming surgery</li><li>Private top surgery: €3,000-6,000</li><li>Private bottom surgery abroad: €15,000-25,000</li></ul><h2 id="costs" tabindex="-1">Costs <a class="header-anchor" href="#costs" aria-label="Permalink to &quot;Costs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Polish Resident</th><th>Non-Resident</th></tr></thead><tbody><tr><td>Sexuology assessment (public)</td><td>Free</td><td>Limited access</td></tr><tr><td>Sexuology assessment (private)</td><td>€50-100</td><td>€50-100</td></tr><tr><td>Endocrinology visit (public)</td><td>Free</td><td>Limited access</td></tr><tr><td>Endocrinology visit (private)</td><td>€40-80</td><td>€40-80</td></tr><tr><td>HRT (monthly)</td><td>€10-30</td><td>€15-40</td></tr></tbody></table><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.ipin.edu.pl/" target="_blank" rel="noreferrer">Institute of Psychiatry and Neurology (Warsaw)</a></li><li><a href="https://transfuzja.org/" target="_blank" rel="noreferrer">Trans-Fuzja Foundation - Healthcare Guide</a></li><li><a href="https://kph.org.pl/" target="_blank" rel="noreferrer">KPH (Campaign Against Homophobia)</a></li><li><a href="https://www.gov.pl/web/zdrowie" target="_blank" rel="noreferrer">Polish Ministry of Health</a></li></ul>',21))])}const P=o(c,[["render",h]]);export{f as __pageData,P as default};
